import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"プラン・コース管理","description":"","frontmatter":{"title":"プラン・コース管理"},"headers":[],"relativePath":"tenant/10-plans.md","filePath":"tenant/10-plans.md"}'),l={name:"tenant/10-plans.md"};function i(o,t,h,n,s,p){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_10-プラン・コース管理" tabindex="-1">10. プラン・コース管理 <a class="header-anchor" href="#_10-プラン・コース管理" aria-label="Permalink to &quot;10. プラン・コース管理&quot;">​</a></h1><p>プラン・コース管理では、食べ放題、飲み放題、セットコース、予約コースなどを設定します。</p><h2 id="時間制プラン" tabindex="-1">時間制プラン <a class="header-anchor" href="#時間制プラン" aria-label="Permalink to &quot;時間制プラン&quot;">​</a></h2><p>食べ放題や飲み放題など、利用時間とラストオーダーが決まっているメニューに利用します。</p><ol><li>プラン名を入力します。</li><li>利用時間、ラストオーダー、価格を設定します。</li><li>対象商品または対象カテゴリを設定します。</li><li>テスト注文で時間表示と会計金額を確認します。</li></ol><p>設定する主な項目:</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>プラン名</td><td>お客様画面やハンディに表示される名称</td></tr><tr><td>利用時間</td><td>何分利用できるか</td></tr><tr><td>ラストオーダー</td><td>終了何分前に注文受付を止めるか</td></tr><tr><td>価格</td><td>プラン料金</td></tr><tr><td>対象メニュー</td><td>プランで注文できる品目</td></tr><tr><td>表示状態</td><td>販売中、非表示、停止など</td></tr></tbody></table><p>時間制プランを使う場合は、対象外の商品が通常注文として混ざらないか、会計時にプラン料金と単品料金が意図通りになるかを必ず確認してください。</p><h2 id="プラン専用メニューcsv" tabindex="-1">プラン専用メニューCSV <a class="header-anchor" href="#プラン専用メニューcsv" aria-label="Permalink to &quot;プラン専用メニューCSV&quot;">​</a></h2><p>プランの対象メニューが多い場合は、CSVで一括更新できます。管理画面の <strong>プラン・コース → 食べ放題プラン</strong> から、プランCSVとメニューCSVを扱います。</p><p>プラン専用メニューCSVでは、プラン名、カテゴリ、品目名、説明、画像、表示順、有効/無効などをまとめて編集できます。インポート後は、対象プランで実際に注文できる品目と、対象外品目が注文できないことをテストしてください。</p><h2 id="コース料理" tabindex="-1">コース料理 <a class="header-anchor" href="#コース料理" aria-label="Permalink to &quot;コース料理&quot;">​</a></h2><p>コース料理では、提供順や構成品目を管理します。予約管理と組み合わせる場合は、予約時に選べるコース内容も確認してください。</p><p>コース料理は、予約管理とKDSの両方に関係します。</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>コース名</td><td>予約時や管理画面に表示</td></tr><tr><td>所要時間</td><td>予約枠や席利用時間の目安</td></tr><tr><td>構成</td><td>前菜、主菜、デザートなどの流れ</td></tr><tr><td>対象メニュー</td><td>実際に提供する品目</td></tr><tr><td>予約表示</td><td>お客様予約画面で選べるか</td></tr></tbody></table><p>コース予約が入る店舗では、予約台帳、ハンディ、KDS、POSレジにコース名や予約文脈が表示されます。アレルギーや注意点がある場合は、コース内容と合わせて確認してください。</p><h2 id="運用時の注意" tabindex="-1">運用時の注意 <a class="header-anchor" href="#運用時の注意" aria-label="Permalink to &quot;運用時の注意&quot;">​</a></h2><ul><li>プラン料金と単品料金の二重計上がないか確認してください。</li><li>ラストオーダー時刻はスタッフ全員に共有してください。</li><li>対象外の商品が注文できないかテストしてください。</li><li>キャンペーン価格を設定する場合は、終了後に戻す運用を決めてください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>プランが表示されない</td><td>販売状態、対象店舗、表示期間を確認してください。</td></tr><tr><td>金額が違う</td><td>プラン価格、オプション、割引を確認してください。</td></tr><tr><td>ラストオーダー後に注文できる</td><td>プラン時間と端末時刻を確認してください。</td></tr><tr><td>コース内容が違う</td><td>コース構成とメニュー登録を確認してください。</td></tr></tbody></table>',20)])])}const _=a(l,[["render",i]]);export{c as __pageData,_ as default};
